const raw =
  $json.output?.[0]?.content?.[0]?.text ||
  $json.message?.content ||
  $json.text ||
  $json.output ||
  JSON.stringify($json);

let parsed;

try {
  parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (error) {
  parsed = {
    type: "unsupported",
    title: "Не вдалося розпізнати повідомлення",
    description: String(raw),
    original_text: String(raw)
  };
}

return [
  {
    json: parsed
  }
];

