const update = $('Telegram Trigger').item.json;
const callback = update.callback_query;

if (!callback?.data) {
  throw new Error('Callback data is missing');
}

const [action, recordId] = callback.data.split('|');

if (!action || !recordId) {
  throw new Error(`Invalid callback format: ${callback.data}`);
}

return [
  {
    json: {
      action,
      record_id: recordId,
      callback_query_id: callback.id,
      telegram_chat_id: String(callback.message.chat.id),
      telegram_user_id: String(callback.from.id),
      telegram_message_id: callback.message.message_id
    }
  }
];

const fields = $json.fields || $json;

if (!fields.Payload) {
  throw new Error('Payload is empty');
}

let payload;

try {
  payload = JSON.parse(fields.Payload);
} catch (error) {
  throw new Error(`Invalid Payload JSON: ${error.message}`);
}

return [
  {
    json: {
      airtable_record_id: $json.id,

      confirmation_id:
        fields['Confirmation ID'] || null,

      intent:
        fields.Intent || null,

      status:
        fields.Status || null,

      telegram_chat_id:
        String(
          fields['Telegram Chat ID']
          || $('Parse Callback Data').item.json.telegram_chat_id
        ),

      telegram_user_id:
        String(
          fields['Telegram User ID']
          || $('Parse Callback Data').item.json.telegram_user_id
        ),

      action:
        $('Parse Callback Data').item.json.action,

      telegram_message_id:
        fields['Telegram Message ID']
        || $('Parse Callback Data').item.json.telegram_message_id
        || null,

      ...payload
    }
  }
];

